---
import type { HTMLAttributes } from "astro/types"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/utils"

interface Props
  extends VariantProps<typeof variants>,
    HTMLAttributes<"div">,
    HTMLAttributes<"a"> {}

const variants = cva(
  "[a]:hover:bg-muted rounded-md border text-sm w-full group/item focus-visible:border-ring focus-visible:ring-ring/50 flex items-center flex-wrap outline-none transition-colors duration-100 focus-visible:ring-[3px] [a]:transition-colors",
  {
    variants: {
      variant: {
        default: "border-transparent",
        outline: "border-border",
        muted: "bg-muted/50 border-transparent",
      },
      size: {
        default: "gap-3.5 px-4 py-3.5",
        sm: "gap-2.5 px-3 py-2.5",
        xs: "gap-2 px-2.5 py-2 in-data-[slot=dropdown-menu-content]:p-0",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "default",
    },
  }
)

const {
  class: className,
  variant = "default",
  size = "default",
  href,
  ...props
} = Astro.props

const Comp = href ? "a" : "div"
---

<Comp
  data-slot="item"
  data-variant={variant}
  data-size={size}
  class={cn(variants({ variant, size }), className)}
  href={href}
  {...props}
>
  <slot />
</Comp>

